mapper.select:
SELECT ev.id as siteEventsId,ev.sort, ev.updater, ev.updated_time, info.sport_type, info.league_name_zh_cn as leagueName, info.league_id,info.id, info.venue_code FROM sport_events_info info left join site_events ev ON ev.events_info_id = info.id and ev.site_code = #{siteCode} WHERE 1 = 1
AND info.sport_type = #{vo.sportType}
AND info.sport_type IN
#{type}
AND info.league_name_cs LIKE CONCAT('%', #{vo.leagueName}, '%')
AND info.league_id = #{vo.leagueId}
ORDER BY CASE WHEN ev.sort IS NOT NULL THEN 0 ELSE info.id END, ev.sort asc, info.id asc
